'use strict';
function createClient(baseUrl, timeout) {
  return {
    async get(path) { return { url: baseUrl + path, status: 200, data: {} }; },
    async post(path, body) { return { url: baseUrl + path, status: 201, data: body }; },
    async delete(path) { return { url: baseUrl + path, status: 204 }; }
  };
}
module.exports = { createClient };

'use strict';
function validateSchema(data, schema) {
  const errors = [];
  for (const [key, rule] of Object.entries(schema)) {
    if (rule.required && data[key] === undefined) errors.push({ field: key, error: 'required' });
    if (rule.type && typeof data[key] !== rule.type) errors.push({ field: key, error: 'type mismatch' });
  }
  return { valid: errors.length === 0, errors };
}
module.exports = { validateSchema };

'use strict';
function adaptLegacyFormat(legacyData) {
  return {
    id: legacyData.ID || legacyData.id,
    name: legacyData.NAME || legacyData.name,
    status: legacyData.STAT || legacyData.status || 'unknown'
  };
}
function convertToLegacy(modernData) {
  return { ID: modernData.id, NAME: modernData.name, STAT: modernData.status };
}
module.exports = { adaptLegacyFormat, convertToLegacy };

'use strict';
const crypto = require('crypto');
function verifySignature(payload, signature, secret) {
  const expected = crypto.createHmac('sha256', secret).update(payload).digest('hex');
  return expected === signature;
}
function parseWebhook(rawBody, headers) {
  const event = headers['x-event-type'] || 'unknown';
  const data = JSON.parse(rawBody);
  return { event, data, receivedAt: Date.now() };
}
module.exports = { verifySignature, parseWebhook };

'use strict';
function createPool(maxConnections) {
  const pool = { active: 0, waiting: [], max: maxConnections };
  return {
    acquire() {
      if (pool.active < pool.max) { pool.active++; return Promise.resolve({ id: pool.active }); }
      return new Promise(resolve => pool.waiting.push(resolve));
    },
    release(conn) { pool.active--; if (pool.waiting.length > 0) { pool.active++; pool.waiting.shift()({ id: pool.active }); } },
    stats() { return { active: pool.active, waiting: pool.waiting.length, max: pool.max }; }
  };
}
module.exports = { createPool };

'use strict';
function createQueue() {
  const queue = [];
  const subscribers = {};
  return {
    publish(topic, message) { queue.push({ topic, message, enqueuedAt: Date.now() }); },
    subscribe(topic, handler) { if (!subscribers[topic]) subscribers[topic] = []; subscribers[topic].push(handler); },
    process() { let count = 0; while (queue.length > 0) { const item = queue.shift(); const handlers = subscribers[item.topic] || []; handlers.forEach(h => h(item.message)); count++; } return count; }
  };
}
module.exports = { createQueue };

'use strict';
function createOAuthClient(config) {
  return {
    getAuthUrl(state) { return config.authEndpoint + '?client_id=' + config.clientId + '&state=' + state; },
    exchangeCode(code) { return { access_token: 'mock_token_' + code, expires_in: 3600 }; },
    refreshToken(token) { return { access_token: 'refreshed_' + token, expires_in: 3600 }; }
  };
}
module.exports = { createOAuthClient };

'use strict';
function createWatcher(paths) {
  const watchers = paths.map(p => ({ path: p, active: true, lastEvent: null }));
  return {
    watch(callback) { watchers.forEach(w => { w.lastEvent = { type: 'watch', timestamp: Date.now() }; }); },
    unwatch(path) { const w = watchers.find(w => w.path === path); if (w) w.active = false; },
    getActive() { return watchers.filter(w => w.active).map(w => w.path); }
  };
}
module.exports = { createWatcher };

'use strict';
function createCache(ttlMs) {
  const store = {};
  return {
    get(key) { const entry = store[key]; if (!entry) return null; if (Date.now() - entry.cachedAt > ttlMs) { delete store[key]; return null; } return entry.value; },
    set(key, value) { store[key] = { value, cachedAt: Date.now() }; },
    invalidate(key) { delete store[key]; },
    size() { return Object.keys(store).length; }
  };
}
module.exports = { createCache };

'use strict';
function createReporter(endpoint) {
  const buffer = [];
  return {
    report(metric, value, tags) { buffer.push({ metric, value, tags: tags || {}, timestamp: Date.now() }); },
    flush() { const batch = buffer.splice(0); return { endpoint, count: batch.length, sentAt: Date.now() }; },
    pending() { return buffer.length; }
  };
}
module.exports = { createReporter };
